const command = `$script = @'
const fs = require('fs');
const source = fs.readFileSync('src/App.jsx', 'utf8');
const helperSource = source.match(/function hasPlusOne[\\s\\S]*?(?=function getTimeLeft)/)[0];
const { getPartySize, countConfirmedAttendees } =
  new Function(helperSource + '; return { getPartySize, countConfirmedAttendees };')();

const statusFor = (confirmed, partySize) =>
  partySize <= 120 - confirmed ? 'Confirmed' : 'Waitlisted';

const checks = [
  ['primary only counts 1', getPartySize({ plusOne: 'No plus-one' }) === 1],
  ['named plus-one counts 2', getPartySize({ plusOne: 'Taylor' }) === 2],
  ['whitespace-only plus-one is absent after form trim', getPartySize({ plusOne: 'No plus-one' }) === 1],
  ['regrets consume 0', countConfirmedAttendees([{ rsvp: 'Regrets', plusOne: 'Taylor' }]) === 0],
  ['waitlisted party consumes 0', countConfirmedAttendees([{ rsvp: 'Waitlisted', plusOne: 'Taylor' }]) === 0],
  ['exact-capacity primary confirms', statusFor(119, 1) === 'Confirmed'],
  ['party exceeding one remaining spot waitlists', statusFor(119, 2) === 'Waitlisted'],
  ['party at full capacity waitlists', statusFor(120, 1) === 'Waitlisted'],
  ['literal non-empty plus-one name "No plus-one" counts 2', getPartySize({ plusOne: 'No plus-one' }) === 2],
];

for (const [name, passed] of checks) {
  console.log((passed ? 'PASS' : 'FAIL') + ' - ' + name);
}

const waitlist = [
  { name: 'First', rsvp: 'Waitlisted' },
  { name: 'Second', rsvp: 'Waitlisted' },
];
console.log(
  (waitlist.filter((guest) => guest.rsvp === 'Waitlisted').map((guest) => guest.name).join(',') === 'First,Second'
    ? 'PASS'
    : 'FAIL') + ' - waitlist retains signup order',
);
'@
$script | node
npm.cmd run build
git diff --check
git status --short`;
